DROP TABLE IF EXISTS `conversation_messages`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `conversation_messages` (
  `message_id` varchar(64) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '消息唯一编号',
  `conversation_id` varchar(64) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '所属会话编号',
  `sequence_no` int NOT NULL COMMENT '会话内消息序号',
  `role` varchar(32) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '消息角色，例如 user、assistant、system',
  `content` longtext COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '消息正文',
  `content_type` varchar(32) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'text' COMMENT '内容类型',
  `model_name` varchar(128) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '生成该消息使用的模型名',
  `token_count` int DEFAULT NULL COMMENT '消息 token 数量',
  `metadata_json` json DEFAULT NULL COMMENT '消息扩展元数据',
  `created_at` datetime NOT NULL COMMENT '创建时间',
  PRIMARY KEY (`message_id`),
  UNIQUE KEY `uk_messages_conversation_sequence` (`conversation_id`,`sequence_no`),
  KEY `idx_messages_conversation_created` (`conversation_id`,`created_at`),
  CONSTRAINT `fk_messages_conversation` FOREIGN KEY (`conversation_id`) REFERENCES `conversations` (`conversation_id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='聊天消息表';
