  `user_id` varchar(128) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '用户编号，当前可为空',
  `title` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '会话标题',
  `status` varchar(32) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'active' COMMENT '会话状态，例如 active、deleted',
  `message_count` int NOT NULL DEFAULT '0' COMMENT '消息数量',
  `summary` text COLLATE utf8mb4_unicode_ci COMMENT '会话摘要',
