  `is_current` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否当前参与训练检索',
  `profile_type` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '历史兼容字段，新上传通常为空',
  `task_type` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '历史兼容字段，新上传通常为空',
  `industry` varchar(128) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '历史兼容字段，新上传通常为空',
  `difficulty` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '历史兼容字段，新上传通常为空',
  `visibility_default` varchar(32) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '默认可见性，例如 visible',
  `status` varchar(32) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '批次状态，例如 pending_review、published、archived',
  `chunk_count` int NOT NULL DEFAULT '0' COMMENT '切片数量',
  `point_count` int NOT NULL DEFAULT '0' COMMENT '当前阶段向量点数量',
  `error_message` text COLLATE utf8mb4_unicode_ci COMMENT '失败原因',
  `quality_report_json` json DEFAULT NULL COMMENT '切片质量报告和发布验证结果',
  `created_by` varchar(128) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '上传人',
  `created_at` datetime NOT NULL COMMENT '创建时间',
  `updated_at` datetime NOT NULL COMMENT '更新时间',
  PRIMARY KEY (`batch_id`),
  KEY `idx_training_batches_md5_status` (`file_md5`,`status`),
  KEY `idx_training_batches_version_group` (`version_group_id`,`version_no`),
  KEY `idx_training_batches_current_status` (`status`,`is_current`,`updated_at`),
  KEY `idx_training_batches_document` (`document_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='销售训练资料上传批次表';
